import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { ArchitectureDoc } from './components/ArchitectureDoc';
import { TransactionsPage } from './components/TransactionsPage';
import { BusinessManager } from './components/BusinessManager';
import { ReportsPage } from './components/ReportsPage';
import { ClientsPage } from './components/ClientsPage';
import { LoginPage } from './components/LoginPage';
import { AIAssistant } from './components/AIAssistant';
import { AccountType, User, Tenant, TransactionType } from './types';

type TabType = 'dashboard' | 'transactions' | 'reports' | 'business' | 'docs' | 'ai-assistant' | 'clients';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [previousTab, setPreviousTab] = useState<TabType | null>(null);
  const [accountMode, setAccountMode] = useState<AccountType>(() => {
    return (localStorage.getItem('fintech_last_mode') as AccountType) || 'BUSINESS';
  });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [user, setUser] = useState<User | null>(null);
  const [tenant, setTenant] = useState<Tenant | null>(null);

  const [isTransactionModalOpen, setIsTransactionModalOpen] = useState(false);
  const [initialTransactionType, setInitialTransactionType] = useState<TransactionType | null>(null);
  const [reportAction, setReportAction] = useState<'print' | null>(null);

  useEffect(() => {
    localStorage.setItem('fintech_last_mode', accountMode);
    // Se mudar para pessoal e estiver na aba clientes (que é business only), volta pro dashboard
    if (accountMode === 'PERSONAL' && activeTab === 'clients') {
      setActiveTab('dashboard');
    }
  }, [accountMode, activeTab]);

  const handleNavigate = (newTab: TabType) => {
    if (newTab !== activeTab) {
      setPreviousTab(activeTab);
      setActiveTab(newTab);
    }
    setIsMobileMenuOpen(false);
  };

  const handleGoBack = () => {
    if (previousTab) {
      setActiveTab(previousTab);
      setPreviousTab(null);
    } else {
      setActiveTab('dashboard');
    }
  };

  const handleLoginSuccess = (data: { user: User; tenant: Tenant; mode: AccountType }) => {
    setUser(data.user);
    setTenant(data.tenant);
    setAccountMode(data.mode);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setTenant(null);
  };

  const handleRequestNewTransaction = (type: TransactionType) => {
    handleNavigate('transactions');
    setInitialTransactionType(type);
    setIsTransactionModalOpen(true);
  };

  const handleRequestReportPDF = () => {
    setReportAction(null);
    setTimeout(() => {
      handleNavigate('reports');
      setReportAction('print');
    }, 50);
  };

  if (!isAuthenticated) {
    return <LoginPage onLoginSuccess={handleLoginSuccess} />;
  }

  const getPageTitle = () => {
    const prefix = accountMode === 'BUSINESS' ? 'Gestão Empresarial' : 'Finanças Pessoais';
    switch(activeTab) {
      case 'dashboard': return `${prefix} • Visão Geral`;
      case 'transactions': return 'Fluxo de Caixa';
      case 'reports': return 'Inteligência de Dados';
      case 'clients': return 'Carteira de Clientes (CRM)';
      case 'business': return 'Parceiros de Negócio';
      case 'docs': return 'Developer Hub';
      case 'ai-assistant': return 'FINTECH AI Assistant';
      default: return 'FINTECH';
    }
  };

  return (
    <div className={`flex min-h-screen font-inter transition-colors duration-500 ${accountMode === 'BUSINESS' ? 'bg-slate-50' : 'bg-emerald-50/30'}`}>
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-950/60 backdrop-blur-md z-40 lg:hidden animate-fadeIn" onClick={() => setIsMobileMenuOpen(false)}></div>
      )}

      <div className={`${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'} fixed lg:relative z-50 transition-transform duration-300`}>
        <Sidebar 
          activeTab={activeTab} 
          setActiveTab={handleNavigate} 
          accountMode={accountMode}
          setAccountMode={setAccountMode}
          onLogout={handleLogout}
          onCloseMobile={() => setIsMobileMenuOpen(false)}
        />
      </div>

      <main className="flex-1 min-h-screen flex flex-col w-full overflow-x-hidden">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-slate-200 px-4 md:px-8 py-3.5 flex items-center justify-between no-print">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsMobileMenuOpen(true)} className="lg:hidden w-11 h-11 flex items-center justify-center rounded-2xl bg-slate-50 border border-slate-200 text-slate-900 active:scale-90 transition-all">
              <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="4" x2="20" y1="12" y2="12"/><line x1="4" x2="20" y1="6" y2="6"/><line x1="4" x2="20" y1="18" y2="18"/></svg>
            </button>

            <div className="flex flex-col">
              <div className="flex items-center gap-1.5 mb-0">
                <span className={`text-[9px] font-black uppercase tracking-widest ${accountMode === 'BUSINESS' ? 'text-slate-400' : 'text-emerald-600'}`}>
                  {accountMode === 'BUSINESS' ? 'Módulo Business' : 'Módulo Pessoal'}
                </span>
                {activeTab !== 'dashboard' && (
                  <>
                    <svg xmlns="http://www.w3.org/2000/svg" width="8" height="8" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" className="text-slate-300"><path d="m9 18 6-6-6-6"/></svg>
                    <span className="text-[9px] font-black text-orange-500 uppercase tracking-widest">{activeTab}</span>
                  </>
                )}
              </div>
              <h1 className="text-base md:text-xl font-black text-slate-900 leading-tight truncate">
                {getPageTitle()}
              </h1>
            </div>
          </div>

          <div className="flex items-center gap-2">
             <div className="flex items-center gap-2.5 bg-slate-50 border border-slate-200 pr-2.5 pl-1 py-1 rounded-2xl hover:bg-white transition-colors cursor-pointer group">
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-white font-black text-xs shadow-md transition-transform ${accountMode === 'BUSINESS' ? 'bg-orange-500' : 'bg-emerald-500'}`}>
                {user?.name.charAt(0)}
              </div>
              <div className="hidden xs:block text-left">
                <p className="text-[10px] font-black text-slate-800 leading-none">{user?.name.split(' ')[0]}</p>
                <p className="text-[8px] font-bold text-slate-400 uppercase tracking-tighter">{tenant?.name}</p>
              </div>
            </div>
          </div>
        </header>

        <section className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full">
          {activeTab === 'dashboard' && (
            <Dashboard 
              mode={accountMode} 
              onRequestNewTransaction={handleRequestNewTransaction}
              onRequestReportPDF={handleRequestReportPDF}
            />
          )}
          {activeTab === 'transactions' && (
            <TransactionsPage 
              mode={accountMode}
              isModalOpen={isTransactionModalOpen}
              onModalClose={() => setIsTransactionModalOpen(false)}
              initialTransactionType={initialTransactionType}
              onModalOpen={() => {
                setInitialTransactionType(null);
                setIsTransactionModalOpen(true);
              }}
            />
          )}
          {activeTab === 'clients' && accountMode === 'BUSINESS' && <ClientsPage />}
          {activeTab === 'reports' && (
            <ReportsPage 
              mode={accountMode}
              onLoadAction={reportAction}
              onActionComplete={() => setReportAction(null)}
              onBack={handleGoBack}
            />
          )}
          {activeTab === 'business' && accountMode === 'BUSINESS' && <BusinessManager />}
          {activeTab === 'docs' && <ArchitectureDoc />}
          {activeTab === 'ai-assistant' && <AIAssistant />}
        </section>

        <footer className="p-6 md:p-8 text-center border-t border-slate-200 no-print">
           <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">FINTECH Ecosystem • {accountMode} Mode Enabled</p>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts';
import { AccountType, Transaction, Category } from '../types';

const TRANSACTIONS_KEY = 'fintech_transactions_v1';
const CATEGORIES_KEY = 'fintech_categories_v1';

// Cores de alto contraste seguindo padrões WCAG
const highContrastColors = ['#000000', '#0000ff', '#ffff00', '#ffffff'];
const highContrastBorders = ['#ffffff', '#ffffff', '#000000', '#000000'];
const standardColors = ['#f97316', '#3b82f6', '#10b981', '#f43f5e', '#8b5cf6', '#64748b'];

interface ReportsPageProps {
  mode: AccountType;
  onLoadAction: 'print' | null;
  onActionComplete: () => void;
  onBack: () => void;
}

export const ReportsPage: React.FC<ReportsPageProps> = ({ mode, onLoadAction, onActionComplete, onBack }) => {
  const [isExportingCSV, setIsExportingCSV] = useState(false);
  const [isPrinting, setIsPrinting] = useState(false);
  const [isHighContrast, setIsHighContrast] = useState(false);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);

  // Carregar dados reais do LocalStorage
  useEffect(() => {
    const loadedTransactions = localStorage.getItem(TRANSACTIONS_KEY);
    const loadedCategories = localStorage.getItem(CATEGORIES_KEY);

    if (loadedTransactions) setTransactions(JSON.parse(loadedTransactions));
    if (loadedCategories) setCategories(JSON.parse(loadedCategories));
  }, []);

  const handleExportPDF = useCallback(() => {
    if (isPrinting) return;
    setIsPrinting(true);
    // Tempo suficiente para os gráficos do Recharts estabilizarem sem animação
    setTimeout(() => {
      window.print();
      setIsPrinting(false);
      onActionComplete();
    }, 800);
  }, [isPrinting, onActionComplete]);

  useEffect(() => {
    if (onLoadAction === 'print') {
      handleExportPDF();
    }
  }, [onLoadAction, handleExportPDF]);

  // Processamento de Dados: Gráfico de Pizza (Despesas por Categoria)
  const categoryData = useMemo(() => {
    const filtered = transactions.filter(t => t.accountType === mode && t.type === 'EXPENSE');
    const aggregation: Record<string, number> = {};

    filtered.forEach(t => {
      const catId = t.categoryId || 'uncategorized';
      aggregation[catId] = (aggregation[catId] || 0) + t.amount;
    });

    return Object.keys(aggregation).map((catId, index) => {
      const cat = categories.find(c => c.id === catId);
      const name = cat ? cat.name : (catId === 'uncategorized' ? 'Sem Categoria' : 'Outros');
      // Tentar usar a cor da categoria (classe Tailwind) convertida para HEX aproximado ou usar paleta padrão
      let color = standardColors[index % standardColors.length];

      return {
        name,
        value: aggregation[catId],
        color: isHighContrast ? highContrastColors[index % highContrastColors.length] : color,
        stroke: isHighContrast ? highContrastBorders[index % highContrastBorders.length] : 'none'
      };
    }).sort((a, b) => b.value - a.value); // Maiores primeiro
  }, [transactions, categories, mode, isHighContrast]);

  // Processamento de Dados: Histórico Mensal para Tabela e CSV
  const historyData = useMemo(() => {
    const filtered = transactions.filter(t => t.accountType === mode);
    const aggregation: Record<string, { income: number; expense: number; date: Date }> = {};

    filtered.forEach(t => {
      const date = new Date(t.date);
      const key = `${date.getFullYear()}-${date.getMonth()}`; // Chave única YYYY-MM

      if (!aggregation[key]) {
        aggregation[key] = { income: 0, expense: 0, date };
      }

      if (t.type === 'INCOME') aggregation[key].income += t.amount;
      else aggregation[key].expense += t.amount;
    });

    return Object.values(aggregation)
      .sort((a, b) => b.date.getTime() - a.date.getTime()) // Mais recente primeiro
      .map(item => {
        const monthName = item.date.toLocaleDateString('pt-MZ', { month: 'long', year: 'numeric' });
        // Capitalizar primeira letra
        return {
          month: monthName.charAt(0).toUpperCase() + monthName.slice(1),
          income: item.income,
          expense: item.expense,
          balance: item.income - item.expense
        };
      });
  }, [transactions, mode]);

  const handleExportCSV = async () => {
    try {
      setIsExportingCSV(true);

      // Cabeçalhos compatíveis com Excel PT-BR/PT-PT (separador ;)
      const headers = ['Mês Referência', 'Total Receitas (MZN)', 'Total Despesas (MZN)', 'Saldo Líquido (MZN)', 'Status'];

      const csvRows = historyData.map(item => [
        `"${item.month}"`, // Aspas para garantir que espaços não quebrem
        item.income.toFixed(2).replace('.', ','), // Formato local
        item.expense.toFixed(2).replace('.', ','),
        item.balance.toFixed(2).replace('.', ','),
        item.balance >= 0 ? 'POSITIVO' : 'NEGATIVO'
      ]);

      const csvContent = [headers.join(';'), ...csvRows.map(row => row.join(';'))].join('\n');

      // Adicionar BOM para suporte a UTF-8 no Excel Windows
      const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });

      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `FINTECH_Relatorio_${mode}_${new Date().toISOString().split('T')[0]}.csv`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } finally {
      setIsExportingCSV(false);
    }
  };

  return (
    <article 
      className={`space-y-8 animate-fadeIn pb-20 transition-colors duration-300 ${isHighContrast ? 'bg-black text-white' : ''}`}
      aria-labelledby="reports-title"
    >
      {/* Botões de Ação e Acessibilidade */}
      <div className="flex flex-wrap justify-between items-center no-print gap-4">
        <button 
          onClick={onBack} 
          className={`group flex items-center gap-2 px-5 py-2.5 rounded-full shadow-sm hover:shadow-md transition-all border ${isHighContrast ? 'bg-zinc-900 border-zinc-700 text-white' : 'bg-white border-slate-200 text-slate-500'}`}
          aria-label="Voltar para a página anterior"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className={isHighContrast ? 'text-yellow-400' : 'text-slate-400 group-hover:text-orange-500'}><path d="m15 18-6-6 6-6"/></svg>
          <span className="text-[11px] font-black uppercase tracking-widest">Voltar</span>
        </button>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => setIsHighContrast(!isHighContrast)}
            className={`px-5 py-2.5 rounded-full border-2 font-black text-[10px] uppercase tracking-widest transition-all flex items-center gap-2 ${isHighContrast ? 'bg-yellow-400 border-yellow-400 text-black' : 'bg-white border-slate-200 text-slate-700'}`}
            aria-pressed={isHighContrast}
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M12 12m-9 0a9 9 0 1 0 18 0a9 9 0 1 0 -18 0"/><path d="M12 3v18"/></svg>
            {isHighContrast ? 'Normal' : 'Alto Contraste'}
          </button>
        </div>
      </div>

      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 no-print">
        <div>
          <h2 id="reports-title" className={`text-3xl font-black tracking-tight ${isHighContrast ? 'text-yellow-400' : 'text-slate-900'}`}>
            Relatórios de Inteligência
          </h2>
          <p className={`${isHighContrast ? 'text-zinc-400' : 'text-slate-500'} font-medium`}>
            Análise detalhada do módulo {mode === 'BUSINESS' ? 'Empresarial' : 'Pessoal'}.
          </p>
        </div>
        <div className="flex flex-wrap gap-3">
           <button onClick={handleExportCSV} disabled={isExportingCSV || historyData.length === 0} className={`px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 border transition-all active:scale-95 ${isHighContrast ? 'bg-zinc-900 border-zinc-700 text-white' : 'bg-white border-slate-200 text-slate-700 hover:bg-slate-50 disabled:opacity-50'}`}>
             <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
             Exportar CSV
           </button>
           <button 
            onClick={handleExportPDF} 
            disabled={isPrinting || historyData.length === 0}
            className={`px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl flex items-center gap-3 active:scale-95 transition-all disabled:opacity-50 disabled:grayscale ${isHighContrast ? 'bg-white text-black' : 'bg-orange-500 text-white shadow-orange-500/20 hover:bg-orange-600'}`}
           >
              <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9V2h12v7"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
              {isPrinting ? 'Gerando...' : 'Imprimir PDF'}
           </button>
        </div>
      </header>

      {/* Cabeçalho exclusivo para impressão */}
      <div className="hidden print:block mb-8 border-b-4 border-black pb-6">
        <h1 className="text-4xl font-black uppercase tracking-tighter">Relatório Consolidado • {mode}</h1>
        <div className="flex justify-between mt-4 font-bold uppercase text-[10px] tracking-widest text-slate-600">
           <span>Emissor: FINTECH SaaS Ecosystem</span>
           <span>Gerado em: {new Date().toLocaleDateString('pt-MZ')} às {new Date().toLocaleTimeString()}</span>
        </div>
      </div>

      {transactions.length === 0 ? (
        <div className="p-12 text-center bg-slate-50 border border-slate-100 rounded-[40px]">
           <p className="text-slate-400 font-bold">Ainda não existem dados suficientes para gerar relatórios.</p>
           <button onClick={onBack} className="mt-4 text-orange-500 text-xs font-black uppercase tracking-widest hover:underline">Registrar transações</button>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <section 
            className={`lg:col-span-2 p-10 rounded-[40px] shadow-sm border chart-container transition-all ${isHighContrast ? 'bg-zinc-900 border-yellow-400' : 'bg-white border-slate-100'}`}
            role="region"
            aria-label="Gráfico de Composição de Despesas"
          >
            <h3 className={`text-lg font-black mb-8 ${isHighContrast ? 'text-yellow-400' : 'text-slate-900'}`}>Composição de Despesas</h3>
            {categoryData.length > 0 ? (
              <div className="h-80 w-full" aria-hidden="true">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie 
                      data={categoryData} 
                      cx="50%" 
                      cy="50%" 
                      innerRadius={70} 
                      outerRadius={110} 
                      paddingAngle={5} 
                      dataKey="value" 
                      isAnimationActive={!isPrinting} // Desativar animação na impressão para garantir renderização
                    >
                      {categoryData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.color} stroke={entry.stroke} strokeWidth={isHighContrast ? 3 : 0} />
                      ))}
                    </Pie>
                    <Tooltip 
                      formatter={(value: number) => `${value.toLocaleString('pt-MZ')} MZN`}
                      contentStyle={isHighContrast ? { backgroundColor: '#000', border: '2px solid #ffff00', color: '#fff' } : { borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                    />
                    <Legend 
                      verticalAlign="bottom" 
                      height={36}
                      formatter={(value) => <span className={`text-[10px] font-black uppercase tracking-widest ${isHighContrast ? 'text-white' : 'text-slate-600'}`}>{value}</span>}
                    />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            ) : (
              <div className="h-80 flex items-center justify-center text-slate-400 text-xs font-bold uppercase tracking-widest">
                Sem despesas no período
              </div>
            )}
            <div className="mt-6 text-[10px] font-bold uppercase tracking-widest text-slate-400 hidden print:block border-t pt-4">
              Nota: Este gráfico representa a distribuição de custos por categoria baseada nos lançamentos registrados.
            </div>
          </section>

          <section 
            className={`p-8 rounded-[40px] shadow-sm border transition-all ${isHighContrast ? 'bg-zinc-900 border-zinc-700' : 'bg-white border-slate-100'}`}
            role="region"
            aria-label="Resumo Mensal de Receitas"
          >
             <h3 className={`text-lg font-black mb-8 ${isHighContrast ? 'text-yellow-400' : 'text-slate-900'}`}>Histórico Mensal</h3>
             <div className="space-y-4 max-h-[400px] overflow-y-auto scrollbar-hide">
                {historyData.map((item, i) => (
                  <div 
                    key={i} 
                    className={`flex flex-col p-4 rounded-2xl border transition-all ${isHighContrast ? 'bg-black border-zinc-700' : 'bg-slate-50 border-slate-100'}`}
                  >
                    <div className="flex justify-between items-center mb-1">
                      <span className={`text-sm font-black ${isHighContrast ? 'text-white' : 'text-slate-900'}`}>{item.month}</span>
                      <span className={`text-xs font-bold ${item.balance >= 0 ? (isHighContrast ? 'text-yellow-400' : 'text-emerald-500') : 'text-rose-500'}`}>
                        {item.balance >= 0 ? '+' : ''}{item.balance.toLocaleString()} MZN
                      </span>
                    </div>
                    <div className="flex justify-between items-center text-[9px] font-bold uppercase tracking-widest opacity-60">
                       <span className={isHighContrast ? 'text-zinc-400' : 'text-slate-500'}>Rec: {item.income.toLocaleString()}</span>
                       <span className={isHighContrast ? 'text-zinc-400' : 'text-slate-500'}>Desp: {item.expense.toLocaleString()}</span>
                    </div>
                  </div>
                ))}
             </div>
          </section>
        </div>
      )}

      <footer className="hidden print:block mt-20 text-center pt-8 border-t border-slate-200">
         <p className="text-[9px] font-black uppercase tracking-[0.5em] text-slate-400">Este documento possui validade fiscal digital confirmada • FINTECH SaaS</p>
         <p className="text-[8px] text-slate-300 mt-2">Hash: {Math.random().toString(36).substring(2, 15).toUpperCase()}</p>
      </footer>
    </article>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { AccountType, Transaction, Category, TransactionType, TransactionStatus, PaymentProvider } from '../types';
import { CategoryManagerModal } from './CategoryManagerModal';
import { MobileMoneyModal } from './MobileMoneyModal';
import { ReceiptTemplate } from './ReceiptTemplate';

const STORAGE_KEY = 'fintech_transactions_v1';
const CATEGORIES_STORAGE_KEY = 'fintech_categories_v1';

// SEED DATA: Categorias Padrão para inicialização do sistema
const DEFAULT_CATEGORIES: Category[] = [
  // Business Income
  { id: 'cat_biz_inc_1', name: 'Vendas de Produtos', icon: '💰', color: 'bg-emerald-500', type: 'INCOME', accountType: 'BUSINESS' },
  { id: 'cat_biz_inc_2', name: 'Serviços Prestados', icon: '💼', color: 'bg-blue-500', type: 'INCOME', accountType: 'BUSINESS' },
  // Business Expense
  { id: 'cat_biz_exp_1', name: 'Fornecedores', icon: '📦', color: 'bg-rose-500', type: 'EXPENSE', accountType: 'BUSINESS' },
  { id: 'cat_biz_exp_2', name: 'Marketing & Ads', icon: '🚀', color: 'bg-indigo-500', type: 'EXPENSE', accountType: 'BUSINESS' },
  { id: 'cat_biz_exp_3', name: 'Operacional / Aluguel', icon: '🏢', color: 'bg-slate-600', type: 'EXPENSE', accountType: 'BUSINESS' },
  { id: 'cat_biz_exp_4', name: 'Salários Equipe', icon: '👥', color: 'bg-amber-500', type: 'EXPENSE', accountType: 'BUSINESS' },
  // Personal Income
  { id: 'cat_pers_inc_1', name: 'Salário Mensal', icon: '💵', color: 'bg-emerald-500', type: 'INCOME', accountType: 'PERSONAL' },
  { id: 'cat_pers_inc_2', name: 'Freelance / Extra', icon: '💻', color: 'bg-cyan-500', type: 'INCOME', accountType: 'PERSONAL' },
  // Personal Expense
  { id: 'cat_pers_exp_1', name: 'Alimentação', icon: '🍔', color: 'bg-orange-500', type: 'EXPENSE', accountType: 'PERSONAL' },
  { id: 'cat_pers_exp_2', name: 'Transporte', icon: '🚗', color: 'bg-slate-500', type: 'EXPENSE', accountType: 'PERSONAL' },
  { id: 'cat_pers_exp_3', name: 'Educação', icon: '📚', color: 'bg-violet-500', type: 'EXPENSE', accountType: 'PERSONAL' },
  { id: 'cat_pers_exp_4', name: 'Lazer', icon: '🎉', color: 'bg-pink-500', type: 'EXPENSE', accountType: 'PERSONAL' },
  // Shared
  { id: 'cat_shared_1', name: 'Bancos & Taxas', icon: '🏦', color: 'bg-gray-500', type: 'EXPENSE', accountType: 'BOTH' },
];

interface TransactionsPageProps {
  mode: AccountType;
  isModalOpen: boolean;
  onModalClose: () => void;
  onModalOpen: () => void;
  initialTransactionType: TransactionType | null;
}

export const TransactionsPage: React.FC<TransactionsPageProps> = ({ mode, isModalOpen, onModalClose, onModalOpen, initialTransactionType }) => {
  const [showFilters, setShowFilters] = useState(false);
  const [isCategoryModalOpen, setIsCategoryModalOpen] = useState(false);
  const [isMobileMoneyModalOpen, setIsMobileMoneyModalOpen] = useState(false);
  const [selectedTransaction, setSelectedTransaction] = useState<Transaction | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [isPrintingReceipt, setIsPrintingReceipt] = useState(false);

  const [searchTerm, setSearchTerm] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [filterStatus, setFilterStatus] = useState<TransactionStatus | 'ALL'>('ALL');

  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formDescription, setFormDescription] = useState('');
  const [formAmount, setFormAmount] = useState<string>('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [formType, setFormType] = useState<TransactionType>('EXPENSE');
  const [formStatus, setFormStatus] = useState<TransactionStatus>('COMPLETED');
  const [formCategoryId, setFormCategoryId] = useState('');
  const [formNotes, setFormNotes] = useState('');
  const [formPaymentMethod, setFormPaymentMethod] = useState<PaymentProvider>('CASH');

  // Inicialização Robusta das Categorias
  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem(CATEGORIES_STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      // Garante que não retorne array vazio se o usuário apagou tudo sem querer, restaura o default
      if (Array.isArray(parsed) && parsed.length > 0) return parsed;
    }
    // Se não houver nada salvo, salva os defaults e retorna
    localStorage.setItem(CATEGORIES_STORAGE_KEY, JSON.stringify(DEFAULT_CATEGORIES));
    return DEFAULT_CATEGORIES;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // Atualiza o tipo do formulário se vier via props (botões rápidos do Dashboard)
  useEffect(() => {
    if (initialTransactionType) {
      setFormType(initialTransactionType);
    }
  }, [initialTransactionType]);

  // Filtrar apenas categorias compatíveis com o modo atual para uso nos Dropdowns
  const filteredCategories = useMemo(() => {
    return categories.filter(c => c.accountType === mode || c.accountType === 'BOTH');
  }, [categories, mode]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(transactions));
  }, [transactions]);

  const handlePrintReceipt = () => {
    if (isPrintingReceipt) return;
    setIsPrintingReceipt(true);
    setTimeout(() => {
      window.print();
      setIsPrintingReceipt(false);
    }, 150);
  };

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesMode = t.accountType === mode;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filterStatus === 'ALL' || t.status === filterStatus;
      const tDate = new Date(t.date).setHours(0,0,0,0);
      const matchesStart = !filterStartDate || tDate >= new Date(filterStartDate).setHours(0,0,0,0);
      const matchesEnd = !filterEndDate || tDate <= new Date(filterEndDate).setHours(0,0,0,0);
      return matchesMode && matchesSearch && matchesStatus && matchesStart && matchesEnd;
    });
  }, [transactions, mode, searchTerm, filterStatus, filterStartDate, filterEndDate]);

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) {
      alert('Preencha os campos obrigatórios.');
      return;
    }
    const transactionData: Transaction = {
      id: editingTransaction?.id || Math.random().toString(36).substr(2, 9),
      amount: parseFloat(formAmount),
      description: formDescription,
      date: formDate,
      type: formType,
      status: formStatus,
      categoryId: formCategoryId,
      tenantId: 't1',
      accountType: mode, // SALVANDO NO CONTEXTO ATUAL
      notes: formNotes,
      paymentMethod: formPaymentMethod,
    };
    if (editingTransaction) setTransactions(transactions.map(t => t.id === editingTransaction.id ? transactionData : t));
    else setTransactions([transactionData, ...transactions]);
    closeAndResetModal();
  };

  const closeAndResetModal = () => {
    onModalClose();
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormDate(new Date().toISOString().split('T')[0]);
    // Não reseta o formType se foi aberto especificamente para Income/Expense
    if (!initialTransactionType) setFormType('EXPENSE');
    setFormStatus('COMPLETED');
    setFormCategoryId('');
    setFormNotes('');
    setFormPaymentMethod('CASH');
  };

  const getStatusBadge = (t: Transaction, isLarge = false) => {
    const status = t.status;
    let colorClass = status === 'COMPLETED' ? "bg-emerald-50 text-emerald-600 border-emerald-100" : status === 'PENDING' ? "bg-amber-50 text-amber-600 border-amber-100" : "bg-rose-50 text-rose-600 border-rose-100";
    let label = status === 'COMPLETED' ? "Efetivado" : status === 'PENDING' ? "Pendente" : "Atrasado";
    return <span className={`${isLarge ? 'px-4 py-2 text-[12px]' : 'px-3 py-1.5 text-[10px]'} rounded-full font-black border uppercase ${colorClass}`}>{label}</span>;
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20 relative">
      {selectedTransaction && (
        <ReceiptTemplate 
          transaction={selectedTransaction} 
          category={categories.find(c => c.id === selectedTransaction.categoryId)}
          tenantName="FINTECH SaaS Moçambique" 
        />
      )}

      <div className="no-print">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
          <div className="flex-1 max-w-2xl w-full">
            <div className="flex items-center gap-3">
              <input 
                type="text" 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder={`Pesquisar no extrato ${mode === 'BUSINESS' ? 'comercial' : 'pessoal'}...`}
                className="w-full px-6 py-4 bg-white border border-slate-200 rounded-[24px] outline-none focus:ring-4 focus:ring-orange-500/10 transition-all font-medium shadow-sm"
              />
              <button onClick={() => setShowFilters(!showFilters)} className={`p-4 rounded-[22px] border transition-all ${showFilters ? 'bg-orange-500 text-white border-orange-500' : 'bg-white border-slate-200 text-slate-500'}`}>
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="21" x2="4" y1="4" y2="4"/><line x1="21" x2="4" y1="12" y2="12"/><line x1="21" x2="4" y1="20" y2="20"/><circle cx="7" cy="4" r="2"/><circle cx="17" cy="12" r="2"/><circle cx="7" cy="20" r="2"/></svg>
              </button>
            </div>
          </div>

          <div className="flex gap-3 w-full lg:w-auto">
            <button onClick={() => setIsCategoryModalOpen(true)} className="px-6 py-4 bg-white border border-slate-200 text-slate-700 rounded-[22px] font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-colors">Categorias</button>
            <button onClick={onModalOpen} className={`flex-1 lg:flex-none px-8 py-4 rounded-[22px] font-black text-xs uppercase tracking-widest shadow-lg active:scale-95 transition-all text-white ${mode === 'BUSINESS' ? 'bg-orange-500 shadow-orange-500/20' : 'bg-emerald-600 shadow-emerald-500/20'}`}>
              Novo Lançamento
            </button>
          </div>
        </div>

        {showFilters && (
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-xl grid grid-cols-1 md:grid-cols-3 gap-6 animate-slideDown mt-6">
            <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value as any)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none">
              <option value="ALL">Todos os Status</option>
              <option value="COMPLETED">Efetivado</option>
              <option value="PENDING">Pendente</option>
              <option value="OVERDUE">Atrasado</option>
            </select>
            <input type="date" value={filterStartDate} onChange={(e) => setFilterStartDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold" />
            <input type="date" value={filterEndDate} onChange={(e) => setFilterEndDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold" />
          </div>
        )}

        <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden mt-8">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Valor</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredTransactions.length === 0 ? (
                   <tr>
                     <td colSpan={5} className="px-8 py-12 text-center text-slate-400 font-bold text-sm">
                       Nenhum lançamento encontrado neste período.
                     </td>
                   </tr>
                ) : (
                  filteredTransactions.map((t) => {
                    const cat = categories.find(c => c.id === t.categoryId);
                    return (
                      <tr key={t.id} onClick={() => setSelectedTransaction(t)} className={`cursor-pointer transition-colors group ${selectedTransaction?.id === t.id ? (mode === 'BUSINESS' ? 'bg-orange-50/50' : 'bg-emerald-50/50') : 'hover:bg-slate-50/50'}`}>
                        <td className="px-8 py-6 text-sm font-bold text-slate-400">{new Date(t.date).toLocaleDateString('pt-MZ', { day: '2-digit', month: 'short' })}</td>
                        <td className="px-8 py-6"><p className="text-sm font-black text-slate-900">{t.description}</p></td>
                        <td className="px-8 py-6">
                          <span className="px-3 py-1.5 rounded-xl text-xs font-black bg-slate-100 text-slate-700 flex items-center gap-2 w-fit">
                            <span>{cat?.icon || '📁'}</span>
                            {cat?.name || 'Geral'}
                          </span>
                        </td>
                        <td className="px-8 py-6">{getStatusBadge(t)}</td>
                        <td className={`px-8 py-6 text-base font-black text-right ${t.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>{t.amount.toLocaleString('pt-MZ')} MZN</td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Modal de Lançamento */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm animate-fadeIn no-print">
          <div className="bg-white rounded-[40px] w-full max-w-xl shadow-2xl overflow-hidden animate-scaleIn flex flex-col max-h-[90vh]">
             <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                <h3 className="text-xl font-black text-slate-900">Novo Registo no Módulo {mode}</h3>
                <button onClick={closeAndResetModal} className="p-2 hover:bg-slate-200 rounded-xl transition-colors"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg></button>
             </div>
             <div className="flex-1 overflow-y-auto p-8 space-y-6">
                <div className="grid grid-cols-2 gap-2 p-1 bg-slate-100 rounded-[22px] border border-slate-200">
                  <button onClick={() => setFormType('EXPENSE')} className={`py-3 rounded-[18px] text-[10px] font-black uppercase tracking-widest transition-all ${formType === 'EXPENSE' ? 'bg-rose-500 text-white shadow-md' : 'text-slate-500'}`}>Despesa</button>
                  <button onClick={() => setFormType('INCOME')} className={`py-3 rounded-[18px] text-[10px] font-black uppercase tracking-widest transition-all ${formType === 'INCOME' ? 'bg-emerald-500 text-white shadow-md' : 'text-slate-500'}`}>Entrada</button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Descrição</label>
                    <input type="text" value={formDescription} onChange={e => setFormDescription(e.target.value)} placeholder="Ex: Pagamento Fornecedor" className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-bold" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Valor (MZN)</label>
                    <input type="number" value={formAmount} onChange={e => setFormAmount(e.target.value)} placeholder="0.00" className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-black" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Data</label>
                    <input type="date" value={formDate} onChange={e => setFormDate(e.target.value)} className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Categoria</label>
                    <select value={formCategoryId} onChange={e => setFormCategoryId(e.target.value)} className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold text-slate-700">
                      <option value="">Selecione...</option>
                      {filteredCategories.filter(c => c.type === formType).map(c => (
                        <option key={c.id} value={c.id}>
                           {c.icon} {c.name}
                        </option>
                      ))}
                    </select>
                    {filteredCategories.filter(c => c.type === formType).length === 0 && (
                       <p className="text-[9px] text-rose-500 mt-1 font-bold ml-1">Nenhuma categoria encontrada para {formType === 'INCOME' ? 'Entradas' : 'Despesas'}. Crie uma nova.</p>
                    )}
                  </div>
                </div>
             </div>
             <div className="p-8 border-t border-slate-100 flex gap-4">
                <button onClick={closeAndResetModal} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-[24px] font-black text-xs uppercase tracking-widest">Cancelar</button>
                <button onClick={handleSaveTransaction} className={`flex-[2] py-5 text-white rounded-[24px] font-black text-xs uppercase tracking-widest shadow-xl transition-all active:scale-95 ${mode === 'BUSINESS' ? 'bg-orange-500 shadow-orange-500/20' : 'bg-emerald-600 shadow-emerald-500/20'}`}>Confirmar Lançamento</button>
             </div>
          </div>
        </div>
      )}

      {/* Detail Drawer */}
      {selectedTransaction && (
        <div className="fixed inset-0 z-[90] flex justify-end bg-slate-950/40 backdrop-blur-[2px] animate-fadeIn no-print" onClick={() => setSelectedTransaction(null)}>
          <div className="w-full max-w-md bg-white h-full shadow-2xl animate-slideLeft flex flex-col" onClick={(e) => e.stopPropagation()}>
            <div className="p-8 border-b border-slate-100 flex items-center justify-between">
              <div><h3 className="text-xl font-black text-slate-900">Detalhes</h3><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">#{selectedTransaction.id}</p></div>
              <button onClick={() => setSelectedTransaction(null)} className="p-3 hover:bg-slate-50 rounded-2xl border border-slate-100"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg></button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-8 text-center">
              <p className={`text-5xl font-black ${selectedTransaction.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>{selectedTransaction.amount.toLocaleString('pt-MZ')} MZN</p>

              <div className="grid grid-cols-2 gap-4 text-left">
                 <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Módulo</p>
                    <p className="text-sm font-black text-slate-900">{selectedTransaction.accountType}</p>
                 </div>
                 <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Status</p>
                    <p className="text-sm font-black text-emerald-600 uppercase">Efetivado</p>
                 </div>
              </div>

              {selectedTransaction.type === 'INCOME' && selectedTransaction.accountType === 'BUSINESS' && (
                <button onClick={handlePrintReceipt} disabled={isPrintingReceipt} className={`w-full py-4 bg-slate-900 text-white rounded-[24px] font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 shadow-xl transition-all active:scale-95`}>
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9V2h12v7"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
                  Imprimir Recibo
                </button>
              )}
            </div>
          </div>
        </div>
      )}

      <CategoryManagerModal isOpen={isCategoryModalOpen} onClose={() => setIsCategoryModalOpen(false)} categories={categories} setCategories={setCategories} currentMode={mode} />
    </div>
  );
};

