// Cores de alto contraste seguindo padrões WCAG
const highContrastColors = ['#000000', '#0000ff', '#ffff00', '#ffffff'];
const highContrastBorders = ['#ffffff', '#ffffff', '#000000', '#000000'];
const standardColors = ['#f97316', '#3b82f6', '#10b981', '#f43f5e', '#8b5cf6', '#64748b'];

interface ReportsPageProps {
  mode: AccountType;
  onLoadAction: 'print' | null;
  onActionComplete: () => void;
  onBack: () => void;
}

export const ReportsPage: React.FC<ReportsPageProps> = ({ mode, onLoadAction, onActionComplete, onBack }) => {
  const [isExportingCSV, setIsExportingCSV] = useState(false);
  const [isPrinting, setIsPrinting] = useState(false);
  const [isHighContrast, setIsHighContrast] = useState(false);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);

  // Carregar dados reais do LocalStorage com Fallback
  useEffect(() => {
    const loadedTransactions = localStorage.getItem(TRANSACTIONS_KEY);
    const loadedCategories = localStorage.getItem(CATEGORIES_KEY);

    if (loadedTransactions) setTransactions(JSON.parse(loadedTransactions));

    if (loadedCategories) {
       const parsed = JSON.parse(loadedCategories);
       if (Array.isArray(parsed) && parsed.length > 0) {
         setCategories(parsed);
       } else {
         setCategories(DEFAULT_CATEGORIES);
       }
    } else {
      setCategories(DEFAULT_CATEGORIES);
    }
  }, []);

  const handleExportPDF = useCallback(() => {
    if (isPrinting) return;
    setIsPrinting(true);
    // Tempo suficiente para os gráficos do Recharts estabilizarem sem animação
    setTimeout(() => {
      window.print();
      setIsPrinting(false);
      onActionComplete();
    }, 800);
  }, [isPrinting, onActionComplete]);

  useEffect(() => {
    if (onLoadAction === 'print') {
      handleExportPDF();
    }
  }, [onLoadAction, handleExportPDF]);

  // Processamento de Dados: Gráfico de Pizza (Despesas por Categoria)
  const categoryData = useMemo(() => {
    const filtered = transactions.filter(t => t.accountType === mode && t.type === 'EXPENSE');
    const aggregation: Record<string, number> = {};

    filtered.forEach(t => {
      const catId = t.categoryId || 'uncategorized';
      aggregation[catId] = (aggregation[catId] || 0) + t.amount;
    });

    return Object.keys(aggregation).map((catId, index) => {
      const cat = categories.find(c => c.id === catId);
      const name = cat ? cat.name : (catId === 'uncategorized' ? 'Sem Categoria' : 'Outros');
      // Tentar usar a cor da categoria (classe Tailwind) convertida para HEX aproximado ou usar paleta padrão
      let color = standardColors[index % standardColors.length];

      return {
        name,
        value: aggregation[catId],
        color: isHighContrast ? highContrastColors[index % highContrastColors.length] : color,
        stroke: isHighContrast ? highContrastBorders[index % highContrastBorders.length] : 'none'
      };
    }).sort((a, b) => b.value - a.value); // Maiores primeiro
  }, [transactions, categories, mode, isHighContrast]);

  // Processamento de Dados: Histórico Mensal para Tabela e CSV
  const historyData = useMemo(() => {
    const filtered = transactions.filter(t => t.accountType === mode);
    const aggregation: Record<string, { income: number; expense: number; date: Date }> = {};

    filtered.forEach(t => {
      const date = new Date(t.date);
      const key = `${date.getFullYear()}-${date.getMonth()}`; // Chave única YYYY-MM

      if (!aggregation[key]) {
        aggregation[key] = { income: 0, expense: 0, date };
      }

      if (t.type === 'INCOME') aggregation[key].income += t.amount;
      else aggregation[key].expense += t.amount;
    });

    return Object.values(aggregation)
      .sort((a, b) => b.date.getTime() - a.date.getTime()) // Mais recente primeiro
      .map(item => {
        const monthName = item.date.toLocaleDateString('pt-MZ', { month: 'long', year: 'numeric' });
        // Capitalizar primeira letra
        return {
          month: monthName.charAt(0).toUpperCase() + monthName.slice(1),
          income: item.income,
          expense: item.expense,
          balance: item.income - item.expense
        };
      });
  }, [transactions, mode]);

  const handleExportCSV = async () => {
    try {
      setIsExportingCSV(true);

      // Cabeçalhos compatíveis com Excel PT-BR/PT-PT (separador ;)
      const headers = ['Mês Referência', 'Total Receitas (MZN)', 'Total Despesas (MZN)', 'Saldo Líquido (MZN)', 'Status'];

      const csvRows = historyData.map(item => [
        `"${item.month}"`, // Aspas para garantir que espaços não quebrem
        item.income.toFixed(2).replace('.', ','), // Formato local
        item.expense.toFixed(2).replace('.', ','),
        item.balance.toFixed(2).replace('.', ','),
        item.balance >= 0 ? 'POSITIVO' : 'NEGATIVO'
      ]);

      const csvContent = [headers.join(';'), ...csvRows.map(row => row.join(';'))].join('\n');

      // Adicionar BOM para suporte a UTF-8 no Excel Windows
      const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });

      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `FINTECH_Relatorio_${mode}_${new Date().toISOString().split('T')[0]}.csv`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } finally {
      setIsExportingCSV(false);
    }
  };

  return (
    <article 
      className={`space-y-8 animate-fadeIn pb-20 transition-colors duration-300 ${isHighContrast ? 'bg-black text-white' : ''}`}
      aria-labelledby="reports-title"
    >
      {/* Botões de Ação e Acessibilidade */}
      <div className="flex flex-wrap justify-between items-center no-print gap-4">
        <button 
          onClick={onBack} 
          className={`group flex items-center gap-2 px-5 py-2.5 rounded-full shadow-sm hover:shadow-md transition-all border ${isHighContrast ? 'bg-zinc-900 border-zinc-700 text-white' : 'bg-white border-slate-200 text-slate-500'}`}
          aria-label="Voltar para a página anterior"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className={isHighContrast ? 'text-yellow-400' : 'text-slate-400 group-hover:text-orange-500'}><path d="m15 18-6-6 6-6"/></svg>
          <span className="text-[11px] font-black uppercase tracking-widest">Voltar</span>
        </button>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => setIsHighContrast(!isHighContrast)}
            className={`px-5 py-2.5 rounded-full border-2 font-black text-[10px] uppercase tracking-widest transition-all flex items-center gap-2 ${isHighContrast ? 'bg-yellow-400 border-yellow-400 text-black' : 'bg-white border-slate-200 text-slate-700'}`}
            aria-pressed={isHighContrast}
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M12 12m-9 0a9 9 0 1 0 18 0a9 9 0 1 0 -18 0"/><path d="M12 3v18"/></svg>
            {isHighContrast ? 'Normal' : 'Alto Contraste'}
          </button>
        </div>
      </div>

      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 no-print">
        <div>
          <h2 id="reports-title" className={`text-3xl font-black tracking-tight ${isHighContrast ? 'text-yellow-400' : 'text-slate-900'}`}>
            Relatórios de Inteligência
          </h2>
          <p className={`${isHighContrast ? 'text-zinc-400' : 'text-slate-500'} font-medium`}>
            Análise detalhada do módulo {mode === 'BUSINESS' ? 'Empresarial' : 'Pessoal'}.
          </p>
        </div>
        <div className="flex flex-wrap gap-3">
           <button onClick={handleExportCSV} disabled={isExportingCSV || historyData.length === 0} className={`px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 border transition-all active:scale-95 ${isHighContrast ? 'bg-zinc-900 border-zinc-700 text-white' : 'bg-white border-slate-200 text-slate-700 hover:bg-slate-50 disabled:opacity-50'}`}>
             <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
             Exportar CSV
           </button>
           <button 
            onClick={handleExportPDF} 
            disabled={isPrinting || historyData.length === 0}
            className={`px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl flex items-center gap-3 active:scale-95 transition-all disabled:opacity-50 disabled:grayscale ${isHighContrast ? 'bg-white text-black' : 'bg-orange-500 text-white shadow-orange-500/20 hover:bg-orange-600'}`}
           >
              <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9V2h12v7"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
              {isPrinting ? 'Gerando...' : 'Imprimir PDF'}
           </button>
        </div>
      </header>

      {/* Cabeçalho exclusivo para impressão */}
      <div className="hidden print:block mb-8 border-b-4 border-black pb-6">
        <h1 className="text-4xl font-black uppercase tracking-tighter">Relatório Consolidado • {mode}</h1>
        <div className="flex justify-between mt-4 font-bold uppercase text-[10px] tracking-widest text-slate-600">
           <span>Emissor: FINTECH SaaS Ecosystem</span>
           <span>Gerado em: {new Date().toLocaleDateString('pt-MZ')} às {new Date().toLocaleTimeString()}</span>
        </div>
      </div>

      {transactions.length === 0 ? (
        <div className="p-12 text-center bg-slate-50 border border-slate-100 rounded-[40px]">
           <p className="text-slate-400 font-bold">Ainda não existem dados suficientes para gerar relatórios.</p>
           <button onClick={onBack} className="mt-4 text-orange-500 text-xs font-black uppercase tracking-widest hover:underline">Registrar transações</button>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <section 
            className={`lg:col-span-2 p-10 rounded-[40px] shadow-sm border chart-container transition-all ${isHighContrast ? 'bg-zinc-900 border-yellow-400' : 'bg-white border-slate-100'}`}
            role="region"
            aria-label="Gráfico de Composição de Despesas"
          >
            <h3 className={`text-lg font-black mb-8 ${isHighContrast ? 'text-yellow-400' : 'text-slate-900'}`}>Composição de Despesas</h3>
            {categoryData.length > 0 ? (
              <div className="h-80 w-full" aria-hidden="true">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie 
                      data={categoryData} 
                      cx="50%" 
                      cy="50%" 
                      innerRadius={70} 
                      outerRadius={110} 
                      paddingAngle={5} 
                      dataKey="value" 
                      isAnimationActive={!isPrinting} // Desativar animação na impressão para garantir renderização
                    >
                      {categoryData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.color} stroke={entry.stroke} strokeWidth={isHighContrast ? 3 : 0} />
                      ))}
                    </Pie>
                    <Tooltip 
                      formatter={(value: number) => `${value.toLocaleString('pt-MZ')} MZN`}
                      contentStyle={isHighContrast ? { backgroundColor: '#000', border: '2px solid #ffff00', color: '#fff' } : { borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                    />
                    <Legend 
                      verticalAlign="bottom" 
                      height={36}
                      formatter={(value) => <span className={`text-[10px] font-black uppercase tracking-widest ${isHighContrast ? 'text-white' : 'text-slate-600'}`}>{value}</span>}
                    />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            ) : (
              <div className="h-80 flex items-center justify-center text-slate-400 text-xs font-bold uppercase tracking-widest">
                Sem despesas no período
              </div>
            )}
            <div className="mt-6 text-[10px] font-bold uppercase tracking-widest text-slate-400 hidden print:block border-t pt-4">
              Nota: Este gráfico representa a distribuição de custos por categoria baseada nos lançamentos registrados.
            </div>
          </section>

          <section 
            className={`p-8 rounded-[40px] shadow-sm border transition-all ${isHighContrast ? 'bg-zinc-900 border-zinc-700' : 'bg-white border-slate-100'}`}
            role="region"
            aria-label="Resumo Mensal de Receitas"
          >
             <h3 className={`text-lg font-black mb-8 ${isHighContrast ? 'text-yellow-400' : 'text-slate-900'}`}>Histórico Mensal</h3>
             <div className="space-y-4 max-h-[400px] overflow-y-auto scrollbar-hide">
                {historyData.map((item, i) => (
                  <div 
                    key={i} 
                    className={`flex flex-col p-4 rounded-2xl border transition-all ${isHighContrast ? 'bg-black border-zinc-700' : 'bg-slate-50 border-slate-100'}`}
                  >
                    <div className="flex justify-between items-center mb-1">
                      <span className={`text-sm font-black ${isHighContrast ? 'text-white' : 'text-slate-900'}`}>{item.month}</span>
                      <span className={`text-xs font-bold ${item.balance >= 0 ? (isHighContrast ? 'text-yellow-400' : 'text-emerald-500') : 'text-rose-500'}`}>
                        {item.balance >= 0 ? '+' : ''}{item.balance.toLocaleString()} MZN
                      </span>
                    </div>
                    <div className="flex justify-between items-center text-[9px] font-bold uppercase tracking-widest opacity-60">
                       <span className={isHighContrast ? 'text-zinc-400' : 'text-slate-500'}>Rec: {item.income.toLocaleString()}</span>
                       <span className={isHighContrast ? 'text-zinc-400' : 'text-slate-500'}>Desp: {item.expense.toLocaleString()}</span>
                    </div>
                  </div>
                ))}
             </div>
          </section>
        </div>
      )}

      <footer className="hidden print:block mt-20 text-center pt-8 border-t border-slate-200">
         <p className="text-[9px] font-black uppercase tracking-[0.5em] text-slate-400">Este documento possui validade fiscal digital confirmada • FINTECH SaaS</p>
         <p className="text-[8px] text-slate-300 mt-2">Hash: {Math.random().toString(36).substring(2, 15).toUpperCase()}</p>
      </footer>
    </article>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Client, Transaction } from '../types';

const CLIENTS_STORAGE_KEY = 'fintech_clients_v1';
const TRANSACTIONS_STORAGE_KEY = 'fintech_transactions_v1';

export const ClientsPage: React.FC = () => {
  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem(CLIENTS_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Supermercado Central', companyName: 'Grupo Central Lda', email: 'compras@central.mz', phone: '841234567', status: 'ACTIVE', totalRevenue: 125000, lastInteraction: '2023-10-15', joinDate: '2023-01-10', tags: ['Varejo', 'VIP'] },
      { id: '2', name: 'Restaurante Marés', companyName: 'Marés Gastronomia', email: 'gerencia@mares.mz', phone: '829876543', status: 'ACTIVE', totalRevenue: 45000, lastInteraction: '2023-10-20', joinDate: '2023-05-15', tags: ['Horeca'] },
      { id: '3', name: 'Tech Solutions', companyName: 'Tech Solutions SA', email: 'admin@techsol.mz', phone: '875551234', status: 'LEAD', totalRevenue: 0, lastInteraction: '2023-11-01', joinDate: '2023-11-01', tags: ['Tecnologia'] }
    ];
  });

  const [transactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem(TRANSACTIONS_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [copied, setCopied] = useState(false);

  // Form States
  const [formName, setFormName] = useState('');
  const [formCompany, setFormCompany] = useState('');
  const [formEmail, setFormEmail] = useState('');
  const [formPhone, setFormPhone] = useState('');
  const [formJoinDate, setFormJoinDate] = useState(new Date().toISOString().split('T')[0]);
  const [formLastInteraction, setFormLastInteraction] = useState(new Date().toISOString().split('T')[0]);

  // Validation States
  const [phoneError, setPhoneError] = useState<string | null>(null);
  const [emailError, setEmailError] = useState<string | null>(null);
  const [dateError, setDateError] = useState<string | null>(null);
  const [formTags, setFormTags] = useState('');

  useEffect(() => {
    localStorage.setItem(CLIENTS_STORAGE_KEY, JSON.stringify(clients));
  }, [clients]);

  // Reset copied state when drawer closes
  useEffect(() => {
    if (!selectedClient) setCopied(false);
  }, [selectedClient]);

  // Validação de Datas em Tempo Real
  useEffect(() => {
    if (formJoinDate && formLastInteraction) {
      const join = new Date(formJoinDate);
      const last = new Date(formLastInteraction);

      if (isNaN(join.getTime()) || isNaN(last.getTime())) {
        setDateError('Datas inválidas.');
      } else if (join > last) {
        setDateError('A data de cadastro não pode ser posterior à última interação.');
      } else {
        setDateError(null);
      }
    }
  }, [formJoinDate, formLastInteraction]);

  // Memoize transações do cliente selecionado para performance
  const clientTransactions = useMemo(() => {
    if (!selectedClient) return [];

    const searchTerms = [
      selectedClient.name.toLowerCase(),
      selectedClient.companyName?.toLowerCase() || ''
    ].filter(term => term.length > 2); // Ignora termos muito curtos

    return transactions
      .filter(t => {
        const desc = t.description.toLowerCase();
        // Verifica se o nome do cliente ou empresa aparece na descrição da transação
        return searchTerms.some(term => desc.includes(term));
      })
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()) // Mais recentes primeiro
      .slice(0, 5); // Limita a 5 itens
  }, [selectedClient, transactions]);

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.companyName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value.replace(/\D/g, '');

    // Limite rigoroso de 9 dígitos
    if (val.length > 9) return;

    setFormPhone(val);

    // Validação de Prefixo e Continuidade
    if (val.length >= 2) {
      const prefix = val.substring(0, 2);
      const validPrefixes = ['82', '83', '84', '85', '86', '87'];

      if (!validPrefixes.includes(prefix)) {
        setPhoneError('Prefixo inválido. Use: 82, 83, 84, 85, 86 ou 87.');
      } else {
        // Prefixo válido, limpar erro para permitir digitação contínua
        setPhoneError(null);
      }
    } else {
      // Menos de 2 dígitos, ainda não validamos
      setPhoneError(null);
    }
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setFormEmail(val);

    // Regex simples para validação de e-mail
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (val && !emailRegex.test(val)) {
      setEmailError('Formato de e-mail inválido.');
    } else {
      setEmailError(null);
    }
  };

  const handleSaveClient = () => {
    // Validação de Campos Obrigatórios
    if (!formName || !formPhone) return;

    // Validação final de comprimento do telefone
    if (formPhone.length !== 9) {
      setPhoneError('O número deve ter exatamente 9 dígitos.');
      return;
    }

    // Verifica se há erros pendentes
    if (phoneError || emailError || dateError) return;

    const newClient: Client = {
      id: Math.random().toString(36).substr(2, 9),
      name: formName,
      companyName: formCompany,
      email: formEmail,
      phone: formPhone,
      status: 'ACTIVE',
      totalRevenue: 0,
      joinDate: formJoinDate,
      lastInteraction: formLastInteraction,
      tags: formTags.split(',').map(t => t.trim()).filter(t => t)
    };

    setClients([newClient, ...clients]);
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setFormName('');
    setFormCompany('');
    setFormEmail('');
    setFormPhone('');
    setFormJoinDate(new Date().toISOString().split('T')[0]);
    setFormLastInteraction(new Date().toISOString().split('T')[0]);
    setPhoneError(null);
    setEmailError(null);
    setDateError(null);
    setFormTags('');
  };

  const openWhatsApp = (phone: string) => {
    const cleanPhone = phone.replace(/\D/g, '');
    const number = cleanPhone.startsWith('258') ? cleanPhone : `258${cleanPhone}`;
    window.open(`https://wa.me/${number}`, '_blank');
  };

  const handleCopyPhone = (phone: string) => {
    navigator.clipboard.writeText(phone);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
           <h2 className="text-xl font-black text-slate-900 tracking-tight">Carteira de Clientes</h2>
           <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de Relacionamento (CRM)</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="px-6 py-4 bg-orange-500 text-white rounded-[22px] font-black text-xs uppercase tracking-widest shadow-xl shadow-orange-500/20 active:scale-95 transition-all flex items-center gap-2"
        >
           <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><line x1="20" x2="20" y1="8" y2="14"/><line x1="23" x2="17" y1="11" y2="11"/></svg>
           Novo Cliente
        </button>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm">
           <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Total de Clientes</p>
           <p className="text-3xl font-black text-slate-900">{clients.length}</p>
        </div>
        <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm">
           <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Clientes Ativos</p>
           <p className="text-3xl font-black text-emerald-500">{clients.filter(c => c.status === 'ACTIVE').length}</p>
        </div>
        <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm">
           <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Receita Total Acumulada</p>
           <p className="text-3xl font-black text-orange-500">{clients.reduce((acc, c) => acc + c.totalRevenue, 0).toLocaleString()} <span className="text-sm text-slate-400">MZN</span></p>
        </div>
      </div>

      {/* Search & Filter */}
      <div className="relative">
        <input 
          type="text" 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          placeholder="Pesquisar por nome, empresa ou e-mail..."
          className="w-full px-6 py-4 pl-12 bg-white border border-slate-200 rounded-[24px] outline-none focus:ring-4 focus:ring-orange-500/10 transition-all font-medium shadow-sm"
        />
        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="absolute left-4 top-4 text-slate-300"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
      </div>

      {/* Clients Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredClients.map(client => (
          <div 
            key={client.id} 
            onClick={() => setSelectedClient(client)}
            className="group bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm hover:shadow-xl hover:shadow-orange-500/5 transition-all cursor-pointer relative overflow-hidden"
          >
             <div className="absolute top-0 right-0 p-6 opacity-0 group-hover:opacity-100 transition-opacity">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="text-orange-500"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/><polyline points="15 3 21 3 21 9"/><line x1="10" x2="21" y1="14" y2="3"/></svg>
             </div>

             <div className="flex items-center gap-4 mb-6">
               <div className="w-14 h-14 rounded-2xl bg-slate-50 flex items-center justify-center text-xl font-black text-slate-300 border border-slate-100 group-hover:bg-orange-500 group-hover:text-white transition-colors">
                  {client.name.charAt(0)}
               </div>
               <div>
                  <h3 className="font-black text-slate-900 leading-tight">{client.name}</h3>
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-wide">{client.companyName || 'Particular'}</p>
               </div>
             </div>

             <div className="space-y-3 mb-6">
                <div className="flex items-center gap-2 text-xs font-medium text-slate-500">
                   <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/></svg>
                   {client.phone}
                </div>
                <div className="flex items-center gap-2 text-xs font-medium text-slate-500">
                   <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect width="20" height="16" x="2" y="4" rx="2"/><path d="m22 7-8.97 5.7a1.94 1.94 0 0 1-2.06 0L2 7"/></svg>
                   {client.email || 'Sem e-mail'}
                </div>
             </div>

             <div className="pt-4 border-t border-slate-50 flex justify-between items-center">
                <div>
                   <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Receita Total</p>
                   <p className="text-sm font-black text-slate-900">{client.totalRevenue.toLocaleString()} MZN</p>
                </div>
                <div className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-wide ${client.status === 'ACTIVE' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>
                   {client.status === 'ACTIVE' ? 'Ativo' : 'Lead'}
                </div>
             </div>
          </div>
        ))}
      </div>

      {/* Add Client Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm animate-fadeIn">
          <div className="bg-white rounded-[40px] w-full max-w-lg shadow-2xl overflow-hidden animate-scaleIn">
             <div className="p-8 border-b border-slate-100 bg-slate-50">
                <h3 className="text-xl font-black text-slate-900">Novo Cliente</h3>
                <p className="text-[10px] font-black text-orange-500 uppercase tracking-widest mt-1">Cadastro de Parceiro de Negócio</p>
             </div>
             <div className="p-8 space-y-5">
                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Nome do Cliente *</label>
                   <input type="text" value={formName} onChange={e => setFormName(e.target.value)} className="w-full px-5 py-3 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-orange-500/10 font-bold" placeholder="Ex: João da Silva" />
                </div>
                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Empresa</label>
                   <input type="text" value={formCompany} onChange={e => setFormCompany(e.target.value)} className="w-full px-5 py-3 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold" placeholder="Ex: Silva Lda" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Telemóvel *</label>
                      <input 
                        type="tel" 
                        value={formPhone} 
                        onChange={handlePhoneChange} 
                        className={`w-full px-5 py-3 bg-slate-50 border rounded-2xl outline-none font-bold transition-all ${phoneError ? 'border-rose-400 focus:ring-rose-500/10' : 'border-slate-200 focus:ring-orange-500/10'}`} 
                        placeholder="84..." 
                        maxLength={9}
                      />
                      {phoneError && (
                        <p className="text-[9px] font-bold text-rose-500 mt-1.5 ml-1 animate-fadeIn">{phoneError}</p>
                      )}
                   </div>
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">E-mail</label>
                      <input 
                        type="email" 
                        value={formEmail} 
                        onChange={handleEmailChange} 
                        className={`w-full px-5 py-3 bg-slate-50 border rounded-2xl outline-none font-bold transition-all ${emailError ? 'border-rose-400 focus:ring-rose-500/10' : 'border-slate-200 focus:ring-orange-500/10'}`} 
                        placeholder="@..." 
                      />
                      {emailError && (
                        <p className="text-[9px] font-bold text-rose-500 mt-1.5 ml-1 animate-fadeIn">{emailError}</p>
                      )}
                   </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Data de Cadastro</label>
                    <input 
                      type="date" 
                      value={formJoinDate} 
                      onChange={e => setFormJoinDate(e.target.value)} 
                      className={`w-full px-5 py-3 bg-slate-50 border rounded-2xl outline-none font-bold transition-all ${dateError ? 'border-rose-400 focus:ring-rose-500/10' : 'border-slate-200 focus:ring-orange-500/10'}`}
                    />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Última Interação</label>
                    <input 
                      type="date" 
                      value={formLastInteraction} 
                      onChange={e => setFormLastInteraction(e.target.value)} 
                      className={`w-full px-5 py-3 bg-slate-50 border rounded-2xl outline-none font-bold transition-all ${dateError ? 'border-rose-400 focus:ring-rose-500/10' : 'border-slate-200 focus:ring-orange-500/10'}`}
                    />
                  </div>
                </div>
                {dateError && (
                  <div className="p-3 bg-rose-50 border border-rose-100 rounded-xl flex items-center gap-2 animate-shake">
                    <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="text-rose-500"><circle cx="12" cy="12" r="10"/><line x1="12" x2="12" y1="8" y2="12"/><line x1="12" x2="12.01" y1="16" y2="16"/></svg>
                    <p className="text-[10px] font-bold text-rose-500">{dateError}</p>
                  </div>
                )}

                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Tags (separadas por vírgula)</label>
                   <input type="text" value={formTags} onChange={e => setFormTags(e.target.value)} className="w-full px-5 py-3 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold" placeholder="Varejo, VIP, Maputo" />
                </div>

                <div className="flex gap-3 pt-4">
                   <button onClick={closeModal} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-[24px] font-black text-xs uppercase tracking-widest">Cancelar</button>
                   <button 
                    onClick={handleSaveClient} 
                    disabled={!!phoneError || !!emailError || !!dateError || !formName || formPhone.length !== 9}
                    className="flex-1 py-4 bg-orange-500 text-white rounded-[24px] font-black text-xs uppercase tracking-widest shadow-xl shadow-orange-500/20 active:scale-95 transition-all disabled:opacity-50 disabled:grayscale"
                   >
                     Salvar Cliente
                   </button>
                </div>
             </div>
          </div>
        </div>
      )}

      {/* Client Details Drawer */}
      {selectedClient && (
        <div className="fixed inset-0 z-[90] flex justify-end bg-slate-950/40 backdrop-blur-[2px] animate-fadeIn" onClick={() => setSelectedClient(null)}>
          <div className="w-full max-w-md bg-white h-full shadow-2xl animate-slideLeft flex flex-col" onClick={(e) => e.stopPropagation()}>
             <div className="p-8 bg-slate-900 text-white">
                <button onClick={() => setSelectedClient(null)} className="mb-6 p-2 bg-white/10 rounded-xl hover:bg-white/20 transition-colors"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg></button>
                <h2 className="text-3xl font-black mb-1">{selectedClient.name}</h2>
                <p className="text-orange-400 font-bold uppercase text-xs tracking-widest">{selectedClient.companyName || 'Cliente Particular'}</p>

                <div className="flex gap-3 mt-6">
                   <button onClick={() => openWhatsApp(selectedClient.phone)} className="flex-1 py-3 bg-emerald-500 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-emerald-400 transition-colors shadow-lg shadow-emerald-500/30">
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/></svg>
                      WhatsApp
                   </button>
                   <button className="flex-1 py-3 bg-white/10 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-white/20 transition-colors">
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect width="20" height="16" x="2" y="4" rx="2"/><path d="m22 7-8.97 5.7a1.94 1.94 0 0 1-2.06 0L2 7"/></svg>
                      E-mail
                   </button>
                </div>
             </div>

             <div className="flex-1 overflow-y-auto p-8 bg-slate-50">
                <div className="bg-white p-6 rounded-[24px] border border-slate-100 shadow-sm mb-6">
                   <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4">Dados de Contato</h3>
                   <div className="space-y-4">
                      <div className="flex justify-between border-b border-slate-50 pb-2 items-center">
                         <span className="text-xs text-slate-400 font-bold">Telemóvel</span>
                         <div className="flex items-center gap-2">
                           <span className="text-xs text-slate-900 font-bold">{selectedClient.phone}</span>
                           <button 
                             onClick={() => handleCopyPhone(selectedClient.phone)}
                             className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-orange-500 transition-colors"
                             title="Copiar número"
                           >
                             {copied ? (
                               <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="text-emerald-500"><polyline points="20 6 9 17 4 12"/></svg>
                             ) : (
                               <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>
                             )}
                           </button>
                         </div>
                      </div>
                      <div className="flex justify-between border-b border-slate-50 pb-2">
                         <span className="text-xs text-slate-400 font-bold">E-mail</span>
                         <span className="text-xs text-slate-900 font-bold">{selectedClient.email || '-'}</span>
                      </div>
                      <div className="flex justify-between border-b border-slate-50 pb-2">
                         <span className="text-xs text-slate-400 font-bold">Cadastro</span>
                         <span className="text-xs text-slate-900 font-bold">{selectedClient.joinDate ? new Date(selectedClient.joinDate).toLocaleDateString('pt-MZ') : '-'}</span>
                      </div>
                      <div className="flex justify-between border-b border-slate-50 pb-2">
                         <span className="text-xs text-slate-400 font-bold">Última Interação</span>
                         <span className="text-xs text-slate-900 font-bold">{new Date(selectedClient.lastInteraction).toLocaleDateString('pt-MZ')}</span>
                      </div>
                      <div className="flex justify-between">
                         <span className="text-xs text-slate-400 font-bold">Status</span>
                         <span className="text-xs text-emerald-500 font-black uppercase">{selectedClient.status}</span>
                      </div>
                   </div>
                </div>

                <div className="bg-white p-6 rounded-[24px] border border-slate-100 shadow-sm">
                   <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4">Histórico Recente</h3>
                   {clientTransactions.length > 0 ? (
                     <div className="space-y-4">
                       {clientTransactions.map(t => (
                         <div key={t.id} className="flex items-center justify-between pb-3 border-b border-slate-50 last:border-0 last:pb-0">
                            <div>
                               <p className="text-xs font-black text-slate-800 truncate max-w-[150px]">{t.description}</p>
                               <p className="text-[10px] text-slate-400 font-bold">{new Date(t.date).toLocaleDateString('pt-MZ')}</p>
                            </div>
                            <p className={`text-xs font-black ${t.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>
                              {t.type === 'INCOME' ? '+' : '-'} {t.amount.toLocaleString()} MZN
                            </p>
                         </div>
                       ))}
                     </div>
                   ) : (
                     <div className="text-center py-6 bg-slate-50 rounded-2xl border border-slate-100 border-dashed">
                        <p className="text-xs text-slate-400 font-medium">Nenhuma transação identificada.</p>
                        <p className="text-[9px] text-slate-300 font-bold mt-1">Dica: Use o nome do cliente na descrição do lançamento.</p>
                     </div>
                   )}
                   <button className="w-full mt-6 py-3 bg-slate-50 text-slate-400 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-100 hover:text-slate-600 transition-colors">Ver Extrato Completo</button>
                </div>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { ArchitectureDoc } from './components/ArchitectureDoc';
import { TransactionsPage } from './components/TransactionsPage';
import { BusinessManager } from './components/BusinessManager';
import { ReportsPage } from './components/ReportsPage';
import { ClientsPage } from './components/ClientsPage';
import { LoginPage } from './components/LoginPage';
import { AIAssistant } from './components/AIAssistant';
import { AccountType, User, Tenant, TransactionType } from './types';

type TabType = 'dashboard' | 'transactions' | 'reports' | 'business' | 'docs' | 'ai-assistant' | 'clients';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [previousTab, setPreviousTab] = useState<TabType | null>(null);
  const [accountMode, setAccountMode] = useState<AccountType>(() => {
    return (localStorage.getItem('fintech_last_mode') as AccountType) || 'BUSINESS';
  });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [user, setUser] = useState<User | null>(null);
  const [tenant, setTenant] = useState<Tenant | null>(null);

  const [isTransactionModalOpen, setIsTransactionModalOpen] = useState(false);
  const [initialTransactionType, setInitialTransactionType] = useState<TransactionType | null>(null);
  const [reportAction, setReportAction] = useState<'print' | null>(null);

  useEffect(() => {
    localStorage.setItem('fintech_last_mode', accountMode);
    // Se mudar para pessoal e estiver na aba clientes (que é business only), volta pro dashboard
    if (accountMode === 'PERSONAL' && activeTab === 'clients') {
      setActiveTab('dashboard');
    }
  }, [accountMode, activeTab]);

  const handleNavigate = (newTab: TabType) => {
    if (newTab !== activeTab) {
      setPreviousTab(activeTab);
      setActiveTab(newTab);
    }
    setIsMobileMenuOpen(false);
  };

  const handleGoBack = () => {
    if (previousTab) {
      setActiveTab(previousTab);
      setPreviousTab(null);
    } else {
      setActiveTab('dashboard');
    }
  };

  const handleLoginSuccess = (data: { user: User; tenant: Tenant; mode: AccountType }) => {
    setUser(data.user);
    setTenant(data.tenant);
    setAccountMode(data.mode);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setTenant(null);
  };

  const handleRequestNewTransaction = (type: TransactionType) => {
    handleNavigate('transactions');
    setInitialTransactionType(type);
    setIsTransactionModalOpen(true);
  };

  const handleRequestReportPDF = () => {
    setReportAction(null);
    setTimeout(() => {
      handleNavigate('reports');
      setReportAction('print');
    }, 50);
  };

  if (!isAuthenticated) {
    return <LoginPage onLoginSuccess={handleLoginSuccess} />;
  }

  const getPageTitle = () => {
    const prefix = accountMode === 'BUSINESS' ? 'Gestão Empresarial' : 'Finanças Pessoais';
    switch(activeTab) {
      case 'dashboard': return `${prefix} • Visão Geral`;
      case 'transactions': return 'Fluxo de Caixa';
      case 'reports': return 'Inteligência de Dados';
      case 'clients': return 'Carteira de Clientes (CRM)';
      case 'business': return 'Parceiros de Negócio';
      case 'docs': return 'Developer Hub';
      case 'ai-assistant': return 'FINTECH AI Assistant';
      default: return 'FINTECH';
    }
  };

  return (
    <div className={`flex min-h-screen font-inter transition-colors duration-500 ${accountMode === 'BUSINESS' ? 'bg-slate-50' : 'bg-emerald-50/30'}`}>
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-950/60 backdrop-blur-md z-40 lg:hidden animate-fadeIn" onClick={() => setIsMobileMenuOpen(false)}></div>
      )}

      <div className={`${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'} fixed lg:relative z-50 transition-transform duration-300`}>
        <Sidebar 
          activeTab={activeTab} 
          setActiveTab={handleNavigate} 
          accountMode={accountMode}
          setAccountMode={setAccountMode}
          onLogout={handleLogout}
          onCloseMobile={() => setIsMobileMenuOpen(false)}
        />
      </div>

      <main className="flex-1 min-h-screen flex flex-col w-full overflow-x-hidden">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-slate-200 px-4 md:px-8 py-3.5 flex items-center justify-between no-print">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsMobileMenuOpen(true)} className="lg:hidden w-11 h-11 flex items-center justify-center rounded-2xl bg-slate-50 border border-slate-200 text-slate-900 active:scale-90 transition-all">
              <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="4" x2="20" y1="12" y2="12"/><line x1="4" x2="20" y1="6" y2="6"/><line x1="4" x2="20" y1="18" y2="18"/></svg>
            </button>

            <div className="flex flex-col">
              <div className="flex items-center gap-1.5 mb-0">
                <span className={`text-[9px] font-black uppercase tracking-widest ${accountMode === 'BUSINESS' ? 'text-slate-400' : 'text-emerald-600'}`}>
                  {accountMode === 'BUSINESS' ? 'Módulo Business' : 'Módulo Pessoal'}
                </span>
                {activeTab !== 'dashboard' && (
                  <>
                    <svg xmlns="http://www.w3.org/2000/svg" width="8" height="8" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" className="text-slate-300"><path d="m9 18 6-6-6-6"/></svg>
                    <span className="text-[9px] font-black text-orange-500 uppercase tracking-widest">{activeTab}</span>
                  </>
                )}
              </div>
              <h1 className="text-base md:text-xl font-black text-slate-900 leading-tight truncate">
                {getPageTitle()}
              </h1>
            </div>
          </div>

          <div className="flex items-center gap-2">
             <div className="flex items-center gap-2.5 bg-slate-50 border border-slate-200 pr-2.5 pl-1 py-1 rounded-2xl hover:bg-white transition-colors cursor-pointer group">
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-white font-black text-xs shadow-md transition-transform ${accountMode === 'BUSINESS' ? 'bg-orange-500' : 'bg-emerald-500'}`}>
                {user?.name.charAt(0)}
              </div>
              <div className="hidden xs:block text-left">
                <p className="text-[10px] font-black text-slate-800 leading-none">{user?.name.split(' ')[0]}</p>
                <p className="text-[8px] font-bold text-slate-400 uppercase tracking-tighter">{tenant?.name}</p>
              </div>
            </div>
          </div>
        </header>

        <section className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full">
          {activeTab === 'dashboard' && (
            <Dashboard 
              mode={accountMode} 
              onRequestNewTransaction={handleRequestNewTransaction}
              onRequestReportPDF={handleRequestReportPDF}
            />
          )}
          {activeTab === 'transactions' && (
            <TransactionsPage 
              mode={accountMode}
              isModalOpen={isTransactionModalOpen}
              onModalClose={() => setIsTransactionModalOpen(false)}
              initialTransactionType={initialTransactionType}
              onModalOpen={() => {
                setInitialTransactionType(null);
                setIsTransactionModalOpen(true);
              }}
              onBack={handleGoBack}
            />
          )}
          {activeTab === 'clients' && accountMode === 'BUSINESS' && <ClientsPage />}
          {activeTab === 'reports' && (
            <ReportsPage 
              mode={accountMode}
              onLoadAction={reportAction}
              onActionComplete={() => setReportAction(null)}
              onBack={handleGoBack}
            />
          )}
          {activeTab === 'business' && accountMode === 'BUSINESS' && <BusinessManager />}
          {activeTab === 'docs' && <ArchitectureDoc />}
          {activeTab === 'ai-assistant' && <AIAssistant />}
        </section>

        <footer className="p-6 md:p-8 text-center border-t border-slate-200 no-print">
           <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">FINTECH Ecosystem • {accountMode} Mode Enabled</p>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { AccountType, Transaction, Category, TransactionType, TransactionStatus, PaymentProvider } from '../types';
import { CategoryManagerModal } from './CategoryManagerModal';
import { MobileMoneyModal } from './MobileMoneyModal';
import { ReceiptTemplate } from './ReceiptTemplate';

const STORAGE_KEY = 'fintech_transactions_v1';
const CATEGORIES_STORAGE_KEY = 'fintech_categories_v1';

// SEED DATA: Categorias Padrão para inicialização do sistema
const DEFAULT_CATEGORIES: Category[] = [
